import React, { useState, useRef } from "react";
import * as sdk from './sdk';

function App() {
  const [result, setResult] = useState("");
  const [recording, setRecording] = useState(false);
  const framesRef = useRef([]);
  const vadIteratorRef = useRef(null);

  const handleStart = async () => {
    setResult('');
    setRecording(true);
    framesRef.current = [];
    vadIteratorRef.current = sdk.recordAndDetectVoice();
    // Collect frames in background
    (async () => {
      for await (const { frame, timestamp } of vadIteratorRef.current) {
        if (!recording) break;
        framesRef.current.push({ frame, timestamp });
      }
    })();
  };

  const handleStopAndUpload = async () => {
    setRecording(false);
    // Simulate encoding frames to a string
    const data = JSON.stringify(framesRef.current.map(f => Array.from(new Uint8Array(f.frame))));
    const key = await sdk.generateKey();
    const encrypted = await sdk.encryptBlob(data, key);
    // Simulate upload
    const blobKey = await sdk.uploadBlob(new Blob([JSON.stringify(encrypted)]), 'https://fake.api', 'token');
    setResult(`Uploaded!\nBlobKey: ${blobKey}\nKey: (in-memory)`);
    // Save for fetch
    window._solaceDemo = { blobKey, key };
  };

  const handleFetchAndDecrypt = async () => {
    const { blobKey, key } = window._solaceDemo || {};
    if (!blobKey || !key) {
      setResult('No blobKey or key found. Please record and upload first.');
      return;
    }
    // Simulate download and decrypt
    const decrypted = await sdk.downloadAndDecrypt(blobKey, 'https://fake.api', key);
    setResult(`Fetched & Decrypted:\n${decrypted}`);
  };

  return (
    <div style={{ padding: 32 }}>
      <h1>Solace Client SDK Demo</h1>
      <button onClick={handleStart} disabled={recording}>Start Recording</button>
      <button onClick={handleStopAndUpload} disabled={!recording}>Stop & Upload</button>
      <button onClick={handleFetchAndDecrypt}>Fetch & Decrypt</button>
      <div style={{ marginTop: 24 }}>
        <strong>Result:</strong>
        <pre>{result}</pre>
      </div>
    </div>
  );
}

export default App;
